def morphological_complexity(word):
    prefix_hits = sum(1 for p in PREFIXES if word.startswith(p) and len(word) > len(p) + 1)
    suffix_hits = sum(1 for s in SUFFIXES if word.endswith(s) and len(word) > len(s) + 1); total = prefix_hits + suffix_hits
