def build_root_mesh(letter_mesh, prefix_map):
    for root in PREFIXES:
        rb = [ord(c) for c in root if ord(c) < 128]
        for i in range(len(rb) - 1):
            letter_mesh[rb[i], rb[i + 1]] += PHI
    for suffix in SUFFIXES:
        sb = [ord(c) for c in suffix if ord(c) < 128]
        for i in range(len(sb) - 1):
            letter_mesh[sb[i], sb[i + 1]] += PHI_INV
        if len(suffix) >= 2:
            for plen in range(1, len(suffix)):
                prefix_map[suffix[:plen]][suffix[plen]] += PHI
    stem_weight = PHI_INV * PHI_INV
    for stem in ROOT_STEMS:
        sb = [ord(c) for c in stem if ord(c) < 128]
        for i in range(len(sb) - 1):
            letter_mesh[sb[i], sb[i + 1]] += stem_weight
        if len(stem) >= 3:
            for plen in range(1, min(len(stem), 6)):
                prefix_map[stem[:plen]][stem[plen]] += stem_weight

def _decode_inline(b64_str):
    return zlib.decompress(_b64.b64decode(b64_str)).decode('utf-8')

def load_dictionary():
    words = [w.strip() for w in _decode_inline(_DICT_B64).split(chr(10)) if w.strip()]
    print(f"  Dictionary loaded: {len(words)} words (inline)")
    return words



def load_story():
    text = _decode_inline(_STORY_B64)
    print(f"  Story loaded: {len(text)} chars (inline)")
    return text
