        self.velocity = self.velocity * PHI_INV + step * PHI_INV; self.position += step
        if self.prev_byte >= 0:
            self.transition_mesh[self.prev_byte][byte_val] += PHI_INV
        if self.prev2_byte >= 0 and self.prev_byte >= 0:
            self.trigram_mesh[(self.prev2_byte, self.prev_byte)][byte_val] += PHI_INV
        self.prev2_byte = self.prev_byte; self.prev_byte = byte_val
