        if first_letter > 0:
            if self._at_sentence_start:
                self._letter_after_start[first_letter] += 1.0; self._total_after_start += 1.0
            if self._prev_word_role > 0.5 and self._prev_word_role < 1.5:
                self._letter_after_det[first_letter] += 1.0; self._total_after_det += 1.0
            if self._prev_word_role > 1.5:
                self._letter_after_prep[first_letter] += 1.0; self._total_after_prep += 1.0
