_VINE_BRIDGE = os.environ.get('VINE_BRIDGE', '1') != '0'            # smoother bridge bias at word starts
_VINE_COHERENCE = float(os.environ.get('VINE_COHERENCE', '1.0'))    # bin threshold (1.0 = original)
