            core_pos / 8.0,                               # normalised position
            tension,                                       # raw tension
            blend * 10.0,                                  # amplified blend weight
            nav_velocity_mag,                              # navigator momentum
            _pw(basin_name_code, [(0,0),(1,0.25),(2,0.5),(3,0.75),(4,1.0)]),  # basin code
            _pw(float(word_len), [(0,0),(3,0.3),(6,0.6),(12,1.0)]),           # word progress
            _pw(float(ppm_count), [(0,0),(10,0.3),(50,0.6),(200,1.0)]),       # PPM evidence
