class NGramBuilder:
    def __init__(self, max_order=MAX_ORDER):
        self.max_order = max_order; self.tables = {n: defaultdict(Counter) for n in range(max_order + 1)}
        self.totals = {n: Counter() for n in range(max_order + 1)}; self.unigram = Counter(); self.uni_total = 0
    def ingest(self, data):
        t0 = time.time()
        for i in range(len(data) - 1):
            nb = data[i + 1]; self.unigram[nb] += 1; self.uni_total += 1
            for order in range(1, min(i + 1, self.max_order) + 1):
                ctx = bytes(data[i + 1 - order:i + 1]); self.tables[order][ctx][nb] += 1; self.totals[order][ctx] += 1
            if (i + 1) % 10_000_000 == 0:
                print(f"    {(i+1)/1e6:.1f}M bytes ({(i+1)/(time.time()-t0)/1e6:.1f} MB/s)")
    def prune(self, min_count=PRUNE_THRESHOLD):
        for order in range(self.max_order + 1):
            p, pt = {}, {}
            for ctx, counts in self.tables[order].items():
                f = {b: c for b, c in counts.items() if c >= min_count}
                if f:
                    p[ctx] = Counter(f); pt[ctx] = sum(f.values())
            self.tables[order] = p; self.totals[order] = pt
    def estimate_memory(self):
        return sum(
            sum(len(ctx) + len(c) * 3 for ctx, c in self.tables[n].items())
            for n in range(self.max_order + 1)
        )
    def compress(self):
        packed = { n: {ctx: sorted(c.items(), key=lambda x: -x[1]) for ctx, c in self.tables[n].items()} for n in range(self.max_order + 1) }
        packed['unigram'] = dict(self.unigram); packed['uni_total'] = self.uni_total; packed['max_order'] = self.max_order
        return zlib.compress(pickle.dumps(packed, protocol=pickle.HIGHEST_PROTOCOL), level=9)
    def ppm_evidence(self, context):
        for order in range(min(len(context), self.max_order), 0, -1):
            ctx_key = bytes(context[-order:]); total = self.totals[order].get(ctx_key, 0)
            if total > 0:
                return total
        return 0
class VINEPredictor:
    def __init__(self, ngrams, dictionary=None, story_words=None):
        self.ngrams = ngrams; self.dictionary = dictionary; self.story_words = story_words
    def predict_for_eval(self, data, max_bytes=None):
        if max_bytes:
            data = data[:max_bytes]
        reader = FieldGraphReader(dictionary=self.dictionary, story_words=self.story_words); reader.set_eval_data(data); reader.math.pre_scan(data)
        total_bits = 0.0; n = 0
        for i in range(len(data) - 1):
            actual = data[i + 1]; context = data[max(0, i + 1 - self.ngrams.max_order):i + 1]; reader.advance_eval_pos(i + 1)
            if not byte_is_letter(data[i]) and i > 0 and byte_is_letter(data[i-1]):
                j = i - 1
                while j >= 0 and byte_is_letter(data[j]):
                    j -= 1
                current_w = bytes(data[j+1:i]).decode('ascii', errors='replace').lower(); k = j - 1
                while k >= 0 and not byte_is_letter(data[k]):
                    k -= 1
                if k >= 0:
                    m = k
                    while m >= 0 and byte_is_letter(data[m]):
                        m -= 1
                    prev_w = bytes(data[m+1:k+1]).decode('ascii', errors='replace').lower(); reader.lookahead.learn_transition(prev_w, current_w)
            ppm_probs = {}; ppm_count = 0
            for order in range(min(len(context), self.ngrams.max_order), 0, -1):
                ctx_key = bytes(context[-order:]); total = self.ngrams.totals[order].get(ctx_key, 0)
                if total > 0:
                    ppm_count = total
                    for bv, c in self.ngrams.tables[order].get(ctx_key, {}).items():
                        ppm_probs[bv] = c / total
                    break
            if not ppm_probs and self.ngrams.uni_total > 0:
                for bv, c in self.ngrams.unigram.items():
                    ppm_probs[bv] = c / self.ngrams.uni_total
            vine_preds = reader.predict_next(data[i], ppm_count=ppm_count); vine_probs = dict(vine_preds); nav_tension = reader.navigator.measure_tension(actual)
            reader.jabberwacky.store(
                reader.navigator.position, nav_tension,
                reader.current_word_letters, actual)
            best_pred = vine_preds[0][0] if vine_preds else -1; reader.correct(actual, best_pred); vw = reader.core.blend_weight(); pw = 1.0 - vw; probs = {}
            for b in set(list(ppm_probs.keys()) + list(vine_probs.keys())):
                probs[b] = pw * ppm_probs.get(b, 0) + vw * vine_probs.get(b, 0)
            for b in range(256):
                if b not in probs:
                    probs[b] = 1e-10
            total = sum(probs.values()); total_bits += -math.log2(max(probs.get(actual, 1e-10) / total, 1e-10)); n += 1
            if n % 100000 == 0:
                emb = reader.embedding
                print(f"    {n} bytes, BPB={total_bits/n:.4f}, basin={reader.core.current_basin_name()}, embed={'alive' if emb.is_alive() else 'dead'} resets={emb.total_resets} decouple={emb.decoupling_events} align={emb.alignment_acc:+.3f} geom_err={emb.geom_error_acc:.3f} full_err={emb.error_acc:.3f}")
        emb = reader.embedding
        print(f"  [embedding telemetry] resets={emb.total_resets} decoupling_events={emb.decoupling_events} final_alignment={emb.alignment_acc:+.3f} geom_err={emb.geom_error_acc:.3f} full_err={emb.error_acc:.3f}")
        return {'val_bpb': total_bits / n, 'bytes': n, 'embed_resets': emb.total_resets, 'embed_decoupling': emb.decoupling_events} if n > 0 else {'val_bpb': float('inf'), 'bytes': 0}
def load_shards(data_path, split="train"):
    dp = Path(data_path)
    for pat in [f"fineweb_{split}_*.bin", f"*{split}*.bin"]:
        s = sorted(dp.glob(pat))
        if s:
            return s
    return None
def extract_story_words(story_text):
    words = re.findall(r'[a-zA-Z]{2,}', story_text.lower())
    return words
def _decode_shard(path, sp, max_tokens, header_bytes=256 * 4):
    header = np.fromfile(path, dtype='<i4', count=256); ntokens = int(header[2])
    toks = np.fromfile(path, dtype='<u2', count=min(ntokens, max_tokens), offset=header_bytes)
    out = b''
    for j in range(0, len(toks), 100000):
        out += sp.decode(toks[j:j+100000].tolist()).encode('utf-8')
    return out

def main():
    import glob, sentencepiece as spm
    t0 = time.time()
    max_order = int(os.environ.get('VINE_MAX_ORDER', '5'))
    data_path = os.environ.get('DATA_PATH', './data/datasets/fineweb10B_sp1024/')
    tokenizer_path = os.environ.get('TOKENIZER_PATH', './data/tokenizers/fineweb_1024_bpe.model')
    eval_bytes = int(os.environ.get('EVAL_BYTES', '500000'))
    eval_offset = int(os.environ.get('EVAL_OFFSET', '0'))
    max_train_shards = int(os.environ.get('MAX_TRAIN_SHARDS', '20'))
    max_tokens_per_shard = int(os.environ.get('MAX_TOKENS_PER_SHARD', '2000000'))

    print("=" * 60); print("VINE Parameter Golf -- Geometric Prediction (non-record)")
    print("=" * 60)
    print(f"  DATA_PATH      = {data_path}")
    print(f"  TOKENIZER_PATH = {tokenizer_path}")
    print(f"  PPM order      = {max_order}")
    print(f"  Eval slice     = {eval_bytes:,} bytes (offset {eval_offset:,})")
    print(f"  Max shards     = {max_train_shards}, max tokens/shard = {max_tokens_per_shard:,}")

    # Verify scoring path integrity (no if/elif in confidence functions)
    for fn in [_pw, byte_is_letter, word_end_probability,
               byte_to_boundary_position, conf_byte_type, conf_word_length,
               conf_mesh, conf_dict, conf_shape, conf_root, conf_ppm,
               conf_structure, conf_basin_agreement, conf_navigator,
               conf_jabberwacky, conf_eleusis, conf_tower,
               conf_caps, conf_digit, conf_symbol, conf_lookahead,
               conf_math, conf_cap_manifold, morphological_complexity,
               classify_basin, word_end_probability]:
        assert 'elif' not in inspect.getsource(fn), f"elif in {fn.__name__}!"
    print("  Scoring path integrity confirmed (no elif in scoring functions)")

    # Resolve shards
    train_shard_paths = sorted(glob.glob(os.path.join(data_path, "fineweb_train_*.bin")))[:max_train_shards]
    val_shard_paths   = sorted(glob.glob(os.path.join(data_path, "fineweb_val_*.bin")))
    if not train_shard_paths or not val_shard_paths:
        print(f"\n  ERROR: no shards found at {data_path}")
        print(f"  Expected files: fineweb_train_*.bin and fineweb_val_*.bin")
        print(f"  Set DATA_PATH and TOKENIZER_PATH env vars to the FineWeb sp1024 cache.")
        sys.exit(1)
    print(f"  Found {len(train_shard_paths)} train shard(s), {len(val_shard_paths)} val shard(s)")

    # Load tokenizer + decode val (always shard 0, full or up to eval_offset+eval_bytes)
    sp = spm.SentencePieceProcessor(model_file=tokenizer_path)
    t = time.time()
    val_bytes = _decode_shard(val_shard_paths[0], sp, max_tokens_per_shard)
    print(f"  Decoded val shard: {len(val_bytes):,} bytes ({time.time()-t:.1f}s)")

    # Load primer assets
    dictionary = load_dictionary(); story_text = load_story()
    story_words = extract_story_words(story_text) if story_text else None
    own_code = Path(__file__).read_bytes()

    # Decode training shards
    t = time.time()
    train_bytes = b''
    for i, sp_path in enumerate(train_shard_paths):
        train_bytes += _decode_shard(sp_path, sp, max_tokens_per_shard)
        print(f"  Decoded train shard {i+1}/{len(train_shard_paths)}: cumulative {len(train_bytes):,} bytes")
    print(f"  Decoded {len(train_shard_paths)} train shards: {len(train_bytes):,} bytes ({time.time()-t:.1f}s)")

    # Build PPM (story + own source + train)
    t = time.time()
    ngrams = NGramBuilder(max_order=max_order)
    if story_text:
        ngrams.ingest(story_text.encode('utf-8'))
    ngrams.ingest(own_code)
    ngrams.ingest(train_bytes)
    est = ngrams.estimate_memory(); thr = PRUNE_THRESHOLD
    while est > TARGET_NGRAM_BYTES and thr < 100:
        thr += 1; ngrams.prune(min_count=thr); est = ngrams.estimate_memory()
    print(f"  PPM built: order={max_order} prune={thr} size={est/1e6:.1f}MB ({time.time()-t:.1f}s)")

    # Eval
    t = time.time()
    val_slice = val_bytes[eval_offset:eval_offset + eval_bytes]
    if len(val_slice) < eval_bytes:
        print(f"  WARNING: requested {eval_bytes:,} bytes at offset {eval_offset:,}, got {len(val_slice):,}")
    predictor = VINEPredictor(ngrams, dictionary=dictionary, story_words=story_words)
    results = predictor.predict_for_eval(val_slice, max_bytes=eval_bytes)
    eval_time = time.time() - t

    if results.get('bytes', 0) == 0 or not (results['val_bpb'] < float('inf')):
        print(f"\n  ERROR: eval produced no valid BPB (bytes={results.get('bytes', 0)})")
        sys.exit(1)

    total = time.time() - t0
    print()
    print("=" * 60)
    print(f"  val_bpb: {results['val_bpb']:.4f}")
    print(f"  bytes evaluated: {results['bytes']:,}")
    print(f"  eval time: {eval_time:.1f}s")
    print(f"  total wall-clock: {total:.1f}s")
    print("=" * 60)

if __name__ == "__main__":
    main()
